"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[3042],{3042:e=>{e.exports=JSON.parse('{"24":{"words":[{"spanish":"Espero que llegues a tiempo","english":"I hope you arrive on time"},{"spanish":"Dudo que \xe9l tenga raz\xf3n","english":"I doubt he is right"},{"spanish":"Es importante que estudies","english":"It is important that you study"},{"spanish":"Me alegra que est\xe9s aqu\xed","english":"I am glad you are here"},{"spanish":"Ojal\xe1 que podamos salir","english":"Hopefully we can go out"},{"spanish":"Recomiendo que hablen con calma","english":"I recommend that you speak calmly"},{"spanish":"Es necesario que haga ejercicio","english":"It is necessary for him or her to exercise"},{"spanish":"No creo que sepan la respuesta","english":"I do not think they know the answer"},{"spanish":"Quiero que me escuches","english":"I want you to listen to me"},{"spanish":"Temo que vaya a llover","english":"I am afraid it might rain"},{"spanish":"Busco un m\xe9dico que sea paciente","english":"I am looking for a doctor who is patient"},{"spanish":"Necesitamos un plan que funcione","english":"We need a plan that works"},{"spanish":"Antes de que te vayas","english":"Before you leave"},{"spanish":"Para que entiendas mejor","english":"So that you understand better"},{"spanish":"Aunque sea dif\xedcil","english":"Even if it is difficult"},{"spanish":"Tal vez venga ma\xf1ana","english":"Maybe he or she will come tomorrow"},{"spanish":"Es extra\xf1o que no responda","english":"It is strange that he or she does not reply"},{"spanish":"Me preocupa que conduzcas cansado","english":"It worries me that you drive while tired"},{"spanish":"Insisto en que me digas la verdad","english":"I insist that you tell me the truth"},{"spanish":"Prefiero que tomemos el tren","english":"I prefer that we take the train"},{"spanish":"Sugiero que revisen el contrato","english":"I suggest that you all review the contract"},{"spanish":"Es mejor que lo hagas hoy","english":"It is better that you do it today"},{"spanish":"No es seguro que podamos entrar","english":"It is not certain that we can get in"},{"spanish":"Ojal\xe1 que el jefe nos d\xe9 permiso","english":"Hopefully the boss gives us permission"},{"spanish":"Me sorprende que sepan tanto","english":"It surprises me that they know so much"},{"spanish":"Es posible que ella vaya sola","english":"It is possible that she goes alone"},{"spanish":"Quieren que yo est\xe9 presente","english":"They want me to be present"},{"spanish":"Dudo que el informe est\xe9 listo","english":"I doubt the report is ready"},{"spanish":"Conviene que descanses","english":"It is advisable that you rest"},{"spanish":"Vale la pena que lo intentes","english":"It is worth trying"},{"spanish":"Ser paciente","english":"To be patient"},{"spanish":"Estar disponible","english":"To be available"},{"spanish":"Ir al grano","english":"To get to the point"},{"spanish":"Tener paciencia","english":"To be patient"},{"spanish":"Hacer una cita","english":"To make an appointment"},{"spanish":"Poder asistir","english":"To be able to attend"},{"spanish":"Saber resolver problemas","english":"To know how to solve problems"},{"spanish":"Dar seguimiento","english":"To follow up"},{"spanish":"La recomendaci\xf3n","english":"The recommendation"},{"spanish":"La duda","english":"The doubt"},{"spanish":"La emoci\xf3n","english":"The emotion"},{"spanish":"El deseo","english":"The wish"}],"conversations":[{"id":1,"topic":"Consulta m\xe9dica y recomendaciones urgentes","dialog":[{"speaker":"Marta","spanish":"Javier, tienes mala cara. Espero que llames al m\xe9dico hoy mismo.","english":"Javier, you look unwell. I hope you call the doctor today."},{"speaker":"Javier","spanish":"S\xed, pero dudo que me den una cita tan r\xe1pido. Siempre est\xe1n ocupados.","english":"Yes, but I doubt they will give me an appointment that quickly. They are always busy."},{"speaker":"Marta","spanish":"Es importante que les expliques que tienes fiebre desde hace tres d\xedas y que no puedes dormir.","english":"It is important that you explain to them that you have had a fever for three days and that you cannot sleep."},{"speaker":"Javier","spanish":"Me alegra que me ayudes, porque no creo que yo est\xe9 pensando con claridad.","english":"I am glad you are helping me, because I do not think I am thinking clearly."},{"speaker":"Marta","spanish":"Recomiendo que no vayas a la oficina ma\xf1ana y que descanses esta noche.","english":"I recommend that you do not go to the office tomorrow and that you rest tonight."},{"speaker":"Javier","spanish":"Ojal\xe1 que la doctora me diga que no es nada grave.","english":"Hopefully the doctor tells me it is nothing serious."}],"questions":[{"question":"\xbfPor qu\xe9 insiste Marta en que Javier llame al m\xe9dico hoy?","options":["Porque quiere cambiar de trabajo","Porque lleva varios d\xedas con fiebre y no duerme bien","Porque necesita pedir vacaciones","Porque tiene que viajar ma\xf1ana"],"answer":"Porque lleva varios d\xedas con fiebre y no duerme bien","answerIndex":1},{"question":"\xbfQu\xe9 duda tiene Javier sobre la cl\xednica?","options":["Que est\xe9 cerrada por reformas","Que la doctora no hable espa\xf1ol","Que le den una cita tan r\xe1pido","Que el seguro ya est\xe9 pagado"],"answer":"Que le den una cita tan r\xe1pido","answerIndex":2},{"question":"\xbfQu\xe9 espera Javier al final de la conversaci\xf3n?","options":["Que le receten antibi\xf3ticos muy fuertes","Que la doctora le diga que no es nada grave","Que Marta vaya a la oficina por \xe9l","Que cancelen todas sus reuniones"],"answer":"Que la doctora le diga que no es nada grave","answerIndex":1}]},{"id":2,"topic":"Proyecto de trabajo con plazos ajustados","dialog":[{"speaker":"Elena","spanish":"Espero que tengas un momento para revisar la propuesta antes de la reuni\xf3n con el cliente.","english":"I hope you have a moment to review the proposal before the meeting with the client."},{"speaker":"Ricardo","spanish":"Claro, aunque dudo que el presupuesto alcance para todas las ideas que presentamos.","english":"Of course, although I doubt the budget will be enough for all the ideas we presented."},{"speaker":"Elena","spanish":"Es necesario que hagamos una versi\xf3n m\xe1s simple y que demos prioridad a las funciones b\xe1sicas.","english":"It is necessary that we make a simpler version and give priority to the basic features."},{"speaker":"Ricardo","spanish":"Me sorprende que el cliente quiera cambios tan grandes en tan poco tiempo.","english":"It surprises me that the client wants such big changes in so little time."},{"speaker":"Elena","spanish":"No creo que acepten otro retraso, as\xed que sugiero que les mostremos un calendario realista.","english":"I do not think they will accept another delay, so I suggest that we show them a realistic schedule."},{"speaker":"Ricardo","spanish":"Est\xe1 bien; ojal\xe1 que valoren la honestidad y que podamos cerrar el acuerdo hoy.","english":"All right; hopefully they value honesty and we can close the deal today."}],"questions":[{"question":"\xbfPor qu\xe9 propone Elena una versi\xf3n m\xe1s simple del proyecto?","options":["Porque el cliente cancel\xf3 la reuni\xf3n","Porque el presupuesto quiz\xe1 no alcance para todo","Porque nadie entiende las funciones b\xe1sicas","Porque Ricardo quiere empezar de cero"],"answer":"Porque el presupuesto quiz\xe1 no alcance para todo","answerIndex":1},{"question":"\xbfQu\xe9 le preocupa a Elena sobre el cliente?","options":["Que no acepte otro retraso","Que cambie de oficina","Que pida una rebaja mayor","Que viaje sin avisar"],"answer":"Que no acepte otro retraso","answerIndex":0},{"question":"\xbfQu\xe9 espera Ricardo al terminar la reuni\xf3n?","options":["Que el cliente contrate a otro equipo","Que valoren la honestidad y cierren el acuerdo","Que suspendan el proyecto por un mes","Que Elena hable sola con el cliente"],"answer":"Que valoren la honestidad y cierren el acuerdo","answerIndex":1}]},{"id":3,"topic":"Planes familiares para una graduaci\xf3n","dialog":[{"speaker":"Sof\xeda","spanish":"Ojal\xe1 que mam\xe1 y pap\xe1 puedan venir a la graduaci\xf3n el s\xe1bado.","english":"Hopefully mom and dad can come to the graduation on Saturday."},{"speaker":"Diego","spanish":"Yo tambi\xe9n lo espero, pero no creo que consigan vuelos baratos a estas alturas.","english":"I hope so too, but I do not think they will find cheap flights this late."},{"speaker":"Sof\xeda","spanish":"Me pone triste que vivan tan lejos, aunque me alegra que siempre intenten acompa\xf1arnos.","english":"It makes me sad that they live so far away, although I am glad they always try to be with us."},{"speaker":"Diego","spanish":"Es posible que viajen en autob\xfas nocturno si no encuentran otra opci\xf3n.","english":"It is possible they will travel on an overnight bus if they do not find another option."},{"speaker":"Sof\xeda","spanish":"Es importante que lleguen descansados; no quiero que pasen toda la noche inc\xf3modos.","english":"It is important that they arrive rested; I do not want them to spend the whole night uncomfortable."},{"speaker":"Diego","spanish":"Tienes raz\xf3n. Recomiendo que les enviemos dinero para que elijan el viaje m\xe1s c\xf3modo.","english":"You are right. I recommend that we send them money so they can choose the most comfortable trip."}],"questions":[{"question":"\xbfQu\xe9 pone triste a Sof\xeda?","options":["Que la graduaci\xf3n sea muy temprano","Que sus padres vivan tan lejos","Que Diego no quiera ayudarlos","Que el autob\xfas salga de otra ciudad"],"answer":"Que sus padres vivan tan lejos","answerIndex":1},{"question":"\xbfQu\xe9 alternativa de transporte menciona Diego?","options":["Un taxi compartido","Un tren regional","Un autob\xfas nocturno","Un vuelo con escala"],"answer":"Un autob\xfas nocturno","answerIndex":2},{"question":"\xbfQu\xe9 soluci\xf3n recomienda Diego para ayudar a los padres?","options":["Enviarles dinero para un viaje m\xe1s c\xf3modo","Cancelar la graduaci\xf3n de este a\xf1o","Reservarles un hotel m\xe1s barato","Pedirle ayuda a un vecino"],"answer":"Enviarles dinero para un viaje m\xe1s c\xf3modo","answerIndex":0}]},{"id":4,"topic":"Voluntariado en el barrio","dialog":[{"speaker":"Carlos","spanish":"Me alegra que quieras ayudar en la campa\xf1a del barrio este fin de semana.","english":"I am glad you want to help in the neighborhood campaign this weekend."},{"speaker":"Laura","spanish":"Claro, pero dudo que tengamos suficientes voluntarios para limpiar el parque y repartir comida.","english":"Of course, but I doubt we will have enough volunteers to clean the park and distribute food."},{"speaker":"Carlos","spanish":"Por eso es importante que hables con tus compa\xf1eros de la universidad hoy mismo.","english":"That is why it is important that you speak with your classmates today."},{"speaker":"Laura","spanish":"Lo har\xe9. Tambi\xe9n sugiero que pidamos al supermercado local que nos done agua y fruta.","english":"I will. I also suggest that we ask the local supermarket to donate water and fruit."},{"speaker":"Carlos","spanish":"Excelente idea. No creo que la gente se anime tanto si no ofrecemos algo b\xe1sico para los voluntarios.","english":"Excellent idea. I do not think people will be as willing if we do not offer something basic for the volunteers."},{"speaker":"Laura","spanish":"Ojal\xe1 que todo salga bien y que m\xe1s vecinos se unan cuando vean el esfuerzo.","english":"Hopefully everything goes well and more neighbors join when they see the effort."}],"questions":[{"question":"\xbfPor qu\xe9 quiere Carlos que Laura hable hoy con sus compa\xf1eros?","options":["Porque necesita vender entradas","Porque faltan voluntarios para la campa\xf1a","Porque deben cambiar la fecha del evento","Porque el supermercado est\xe1 cerrado"],"answer":"Porque faltan voluntarios para la campa\xf1a","answerIndex":1},{"question":"\xbfQu\xe9 donaci\xf3n propone Laura pedir?","options":["Mesas y sillas","Guantes y escobas","Agua y fruta","Libros y cuadernos"],"answer":"Agua y fruta","answerIndex":2},{"question":"Seg\xfan Carlos, \xbfqu\xe9 puede animar m\xe1s a los voluntarios?","options":["Ofrecer algo b\xe1sico durante la jornada","Reducir el trabajo a una sola hora","Hacer la campa\xf1a en otro barrio","Suspender la limpieza del parque"],"answer":"Ofrecer algo b\xe1sico durante la jornada","answerIndex":0}]}],"stories":[{"id":1,"title":"La cita con la especialista","sentences":[{"spanish":"Laura llevaba semanas con migra\xf1as, as\xed que su hermana insisti\xf3 en que pidiera una cita con una especialista.","english":"Laura had been dealing with migraines for weeks, so her sister insisted that she make an appointment with a specialist."},{"spanish":"Laura dudaba que el seguro cubriera la consulta, pero le alegr\xf3 que la cl\xednica respondiera el mismo d\xeda.","english":"Laura doubted that her insurance would cover the visit, but she was glad the clinic replied the same day."},{"spanish":"La recepcionista recomend\xf3 que llegara temprano y que llevara todos sus an\xe1lisis anteriores.","english":"The receptionist recommended that she arrive early and bring all her previous test results."},{"spanish":"Antes de que saliera de casa, su madre le record\xf3 que comiera algo ligero y que tomara agua.","english":"Before she left home, her mother reminded her to eat something light and drink water."},{"spanish":"Ojal\xe1 que la doctora encontrara una soluci\xf3n simple, pens\xf3 Laura mientras esperaba en la sala.","english":"Hopefully the doctor would find a simple solution, Laura thought while waiting in the room."},{"spanish":"Al final, Laura sinti\xf3 alivio porque era posible que el tratamiento funcionara sin interrumpir su trabajo.","english":"In the end, Laura felt relieved because it was possible the treatment would work without interrupting her job."}]},{"id":2,"title":"Un proyecto delicado","sentences":[{"spanish":"El equipo esperaba que el cliente aceptara una propuesta m\xe1s modesta despu\xe9s de varias semanas de cambios.","english":"The team hoped the client would accept a more modest proposal after several weeks of changes."},{"spanish":"Ricardo dudaba que el presupuesto alcanzara, as\xed que pidi\xf3 que revisaran cada gasto con mucho detalle.","english":"Ricardo doubted the budget would be enough, so he asked that they review every expense in detail."},{"spanish":"A Elena le molestaba que el cliente cambiara de opini\xf3n a \xfaltima hora, pero sab\xeda que conven\xeda mantener la calma.","english":"Elena was bothered that the client kept changing their mind at the last minute, but she knew it was wise to stay calm."},{"spanish":"Antes de que empezara la reuni\xf3n, ambos acordaron hablar con total honestidad.","english":"Before the meeting started, they both agreed to speak with complete honesty."},{"spanish":"Les alegr\xf3 que el cliente valorara el calendario realista en lugar de exigir promesas imposibles.","english":"They were glad the client valued the realistic timeline instead of demanding impossible promises."},{"spanish":"Al salir, pensaron que val\xeda la pena que el equipo siguiera trabajando con esa misma transparencia.","english":"When they left, they thought it was worth it for the team to keep working with that same transparency."}]},{"id":3,"title":"La graduaci\xf3n esperada","sentences":[{"spanish":"Sof\xeda so\xf1aba con que sus padres estuvieran presentes el d\xeda de su graduaci\xf3n universitaria.","english":"Sof\xeda dreamed that her parents would be present on the day of her university graduation."},{"spanish":"Aunque no cre\xeda que encontraran vuelos baratos, le emocionaba que siguieran buscando opciones.","english":"Although she did not think they would find cheap flights, she was moved that they kept looking for options."},{"spanish":"Diego sugiri\xf3 que les enviaran dinero para que viajaran con m\xe1s comodidad.","english":"Diego suggested that they send them money so they could travel more comfortably."},{"spanish":"Su madre pidi\xf3 que nadie cambiara los planes hasta confirmar el horario del autob\xfas nocturno.","english":"Her mother asked that no one change the plans until they confirmed the overnight bus schedule."},{"spanish":"A Sof\xeda le alegr\xf3 much\xedsimo que, al final, sus padres pudieran llegar antes de la ceremonia.","english":"Sof\xeda was thrilled that, in the end, her parents were able to arrive before the ceremony."},{"spanish":"Cuando los vio entrar, sinti\xf3 que todo el esfuerzo hab\xeda valido la pena.","english":"When she saw them walk in, she felt that every bit of effort had been worth it."}]}],"speaking":{"title":"Pr\xe1ctica oral del presente de subjuntivo","description":"Responde con deseos, dudas, emociones y recomendaciones usando el presente de subjuntivo.","questions_and_answers":[{"question":{"spanish":"Di en espa\xf1ol: I hope you come early tomorrow.","english":"Say in Spanish: I hope you come early tomorrow."},"answer":{"spanish":"Espero que vengas temprano ma\xf1ana.","english":"I hope you come early tomorrow."}},{"question":{"spanish":"Di en espa\xf1ol: I doubt he has enough money for the deposit.","english":"Say in Spanish: I doubt he has enough money for the deposit."},"answer":{"spanish":"Dudo que \xe9l tenga suficiente dinero para el dep\xf3sito.","english":"I doubt he has enough money for the deposit."}},{"question":{"spanish":"Di en espa\xf1ol: It is important that you are honest with your team.","english":"Say in Spanish: It is important that you are honest with your team."},"answer":{"spanish":"Es importante que seas honesto con tu equipo.","english":"It is important that you are honest with your team."}},{"question":{"spanish":"Di en espa\xf1ol: I am glad you are feeling better after the treatment.","english":"Say in Spanish: I am glad you are feeling better after the treatment."},"answer":{"spanish":"Me alegra que est\xe9s mejor despu\xe9s del tratamiento.","english":"I am glad you are feeling better after the treatment."}},{"question":{"spanish":"Di en espa\xf1ol: Hopefully we can finish before six.","english":"Say in Spanish: Hopefully we can finish before six."},"answer":{"spanish":"Ojal\xe1 que podamos terminar antes de las seis.","english":"Hopefully we can finish before six."}},{"question":{"spanish":"Di en espa\xf1ol: I recommend that you go by subway to avoid traffic.","english":"Say in Spanish: I recommend that you go by subway to avoid traffic."},"answer":{"spanish":"Recomiendo que vayan en metro para evitar el tr\xe1fico.","english":"I recommend that you go by subway to avoid traffic."}},{"question":{"spanish":"Di en espa\xf1ol: It is necessary that he make a copy of the contract.","english":"Say in Spanish: It is necessary that he make a copy of the contract."},"answer":{"spanish":"Es necesario que haga una copia del contrato.","english":"It is necessary that he make a copy of the contract."}},{"question":{"spanish":"Di en espa\xf1ol: I do not think they know how to get there without a map.","english":"Say in Spanish: I do not think they know how to get there without a map."},"answer":{"spanish":"No creo que sepan c\xf3mo llegar sin un mapa.","english":"I do not think they know how to get there without a map."}},{"question":{"spanish":"Di en espa\xf1ol: I want you to give me a clear answer today.","english":"Say in Spanish: I want you to give me a clear answer today."},"answer":{"spanish":"Quiero que me des una respuesta clara hoy.","english":"I want you to give me a clear answer today."}},{"question":{"spanish":"Di en espa\xf1ol: I am afraid the child may not sleep well in the hospital.","english":"Say in Spanish: I am afraid the child may not sleep well in the hospital."},"answer":{"spanish":"Temo que el ni\xf1o no duerma bien en el hospital.","english":"I am afraid the child may not sleep well in the hospital."}},{"question":{"spanish":"Di en espa\xf1ol: It is advisable that you drink water before running.","english":"Say in Spanish: It is advisable that you drink water before running."},"answer":{"spanish":"Conviene que tomes agua antes de correr.","english":"It is advisable that you drink water before running."}},{"question":{"spanish":"Di en espa\xf1ol: It is possible that she comes from Bogot\xe1 tonight.","english":"Say in Spanish: It is possible that she comes from Bogot\xe1 tonight."},"answer":{"spanish":"Es posible que ella venga desde Bogot\xe1 esta noche.","english":"It is possible that she comes from Bogot\xe1 tonight."}},{"question":{"spanish":"Di en espa\xf1ol: I am looking for an apartment that has a balcony and good light.","english":"Say in Spanish: I am looking for an apartment that has a balcony and good light."},"answer":{"spanish":"Busco un apartamento que tenga balc\xf3n y buena luz.","english":"I am looking for an apartment that has a balcony and good light."}},{"question":{"spanish":"Di en espa\xf1ol: I prefer that we are seated near the exit.","english":"Say in Spanish: I prefer that we are seated near the exit."},"answer":{"spanish":"Prefiero que estemos sentados cerca de la salida.","english":"I prefer that we are seated near the exit."}},{"question":{"spanish":"Di en espa\xf1ol: I insist that you tell him the whole truth.","english":"Say in Spanish: I insist that you tell him the whole truth."},"answer":{"spanish":"Insisto en que le digas toda la verdad.","english":"I insist that you tell him the whole truth."}},{"question":{"spanish":"Di en espa\xf1ol: Before you all leave, check the passports.","english":"Say in Spanish: Before you all leave, check the passports."},"answer":{"spanish":"Antes de que salgan, revisen los pasaportes.","english":"Before you all leave, check the passports."}},{"question":{"spanish":"Di en espa\xf1ol: So that you can concentrate, turn off the cell phone.","english":"Say in Spanish: So that you can concentrate, turn off the cell phone."},"answer":{"spanish":"Para que puedas concentrarte, apaga el celular.","english":"So that you can concentrate, turn off the cell phone."}},{"question":{"spanish":"Di en espa\xf1ol: It surprises me that the boss goes to the negotiation alone.","english":"Say in Spanish: It surprises me that the boss goes to the negotiation alone."},"answer":{"spanish":"Me sorprende que el jefe vaya solo a la negociaci\xf3n.","english":"It surprises me that the boss goes to the negotiation alone."}},{"question":{"spanish":"Di en espa\xf1ol: It is not certain that the store opens on Sunday.","english":"Say in Spanish: It is not certain that the store opens on Sunday."},"answer":{"spanish":"No es seguro que la tienda abra en domingo.","english":"It is not certain that the store opens on Sunday."}},{"question":{"spanish":"Di en espa\xf1ol: It is worth it for us to try one more time.","english":"Say in Spanish: It is worth it for us to try one more time."},"answer":{"spanish":"Vale la pena que lo intentemos una vez m\xe1s.","english":"It is worth it for us to try one more time."}}]}}}')}}]);